# coding: utf-8
import hashlib
import io
import json
import os
from typing import List, Optional

import requests
from urllib3.exceptions import InsecureRequestWarning

from rainbow_admin.errors import RainbowException
from rainbow_admin.group import BaseGroup
from rainbow_admin.utils import logger


class FileDeployInfo(object):
    def __init__(
        self,
        path: str,
        before_shell: str = "",
        after_shell: str = "",
        client_shell: str = "",
        client_switch: bool = False,
        executor: str = None,
        **kwargs
    ):
        """
        :param path: 文件下载临时目录
        :param before_shell: 前置命令
        :param after_shell: 后置命令
        :param client_shell: 抓取客户端标识的 shell 语句
        :param client_switch: 是否开启抓取客户端标识
        :param executor: """
        self.path = path
        self.after_shell = after_shell
        self.before_shell = before_shell
        self.client_shell = client_shell
        self.client_switch = client_switch
        self.executor = executor


class RainbowFile(object):
    """
    这是对文件（通常是cos文件）的封装。在以下地方会复用到，修改时需注意兼容性
    1. 七彩石文件分组--Done
    2. 通用模板文件--Doing
    3. 智研场景的模板文件--TODO
    """
    def __init__(
        self,
        key,
        value,
        value_type=0,
        description="",
        group: "FileGroup" = None,
        **kwargs,
    ):
        self.key = key
        self.value = value
        self.value_type = value_type
        self.description = description
        self.status = kwargs.get("status")
        self.info = kwargs
        self.id = kwargs.get("id")
        self.operator = kwargs.get("operator")

        self.group = group
        self.file_info = json.loads(self.value)
        self.filename = os.path.basename(self.key)
        self.file_version = self.file_info["file_version"]
        self.is_editable = self.file_info["is_editable"]
        self.is_gbk = self.file_info["is_gbk"]
        self.md5 = self.file_info["md5"]
        self.mtime = self.file_info["mtime"]
        self.size = self.file_info["size"]
        self.url = self.file_info["url"]
        self.secret_key = self.file_info.get("secret_key")
        self.secret_key_md5 = self.file_info.get("secret_key_md5")
        self.name = self.file_info["name"]

        self.is_intranet = kwargs.get("is_intranet")

    @property
    def real_url(self):
        return f"{self.url}?versionId={self.file_version}"

    def requests_headers(self):
        if not self.secret_key:
            return {}
        return {
            "x-cos-server-side-encryption-customer-algorithm": "AES256",
            "x-cos-server-side-encryption-customer-key": self.secret_key,
            "x-cos-server-side-encryption-customer-key-MD5": self.secret_key_md5,
        }

    def requests_kwargs(self):
        """从北极星获取的内网地址下载加密文件时，关闭证书验证
        """
        if self.is_intranet and self.secret_key:
            return {
                "method": "GET",
                "url": self.real_url,
                "headers": self.requests_headers(),
                "verify": False,
            }
        return {
            "method": "GET",
            "url": self.real_url,
            "headers": self.requests_headers(),
        }

    def download_to(self, path, with_dir=False):
        """下载到指定文件或目录"""
        key = self.key.lstrip("/")
        if os.path.isdir(path):
            if with_dir:
                path = os.path.join(path, key)
            else:
                path = os.path.join(path, self.filename)
        path = os.path.abspath(path)
        file_dir = os.path.dirname(path)
        if not os.path.isdir(file_dir):
            os.makedirs(file_dir, exist_ok=True)
        logger.info(f"downloading... {key} => {path}")
        if os.path.isfile(path):
            md5 = hashlib.md5()
            with open(path, "rb") as f:
                chunk = f.read(8192)
                while chunk:
                    md5.update(chunk)
                    chunk = f.read(8192)
            if self.md5 == md5.hexdigest().lower():
                logger.info(f"file exist and md5 equal, download skip: {key}")
                return
            else:
                logger.info(f"will cover {path}")

        kwargs = self.requests_kwargs()
        kwargs.setdefault("stream", True)

        if self.is_intranet:
            requests.packages.urllib3.disable_warnings(category=InsecureRequestWarning)

        with requests.request(**kwargs) as r:
            r.raise_for_status()
            with open(path, "wb") as f:
                for chunk in r.iter_content(chunk_size=8192):
                    f.write(chunk)

    def text(self):
        """返回此文件的文本内容"""
        if not self.is_editable:
            raise ValueError("此文件非文本文件")
        kwargs = self.requests_kwargs()
        return requests.request(**kwargs).text

    def content(self):
        """返回此文件的二进制内容"""
        kwargs = self.requests_kwargs()
        return requests.request(**kwargs).content

    def set_text(self, content):
        """修改文件内容"""
        return self.upload(io.BytesIO(content.encode("utf-8")))

    def upload(self, file):
        """更新文件"""
        return self.group.upload_file(self.key, file)

    def to_dict(self):
        ans = {
            "id": self.id,
            "key": self.key,
            "description": self.description,
            "group_id": self.group.group_id,
        }
        ans.update(self.file_info)
        return ans

    def delete(self):
        return self.group.delete_file(self.key)

    def __str__(self) -> str:
        return f"{self.__class__.__name__}({self.key})"

    __repr__ = __str__


class FileGroup(BaseGroup):
    CONFIG_TYPE = 2
    cos_cl5 = "1084865:196608"
    cos_host = "rainbow-1258344702.cos.ap-guangzhou.myqcloud.com"
    is_intranet = False
    cl5_resolve_lib = "auto"

    def upload_file(self, filename, file, description="", need_uncompress=False, full_replace=None):
        """上传文件

        :param filename: 在rainbow显示的文件名
        :param file: 文本，或者可读类型，或者是二进制。如果是文本，会转成utf-8
        :param description: 文件描述
        :param need_uncompress: 是否要自动解压
        :param full_replace: 是否覆盖上传
        :return:
        """
        if not hasattr(file, "read"):
            if isinstance(file, str):
                file = io.BytesIO(file.encode("utf-8"))
            elif isinstance(file, bytes):
                file = io.BytesIO(file)
            else:
                raise ValueError(f"参数file不可读： {file}")
        if filename in self:
            logger.info(f"upload and cover: {filename}")
        else:
            logger.info(f"upload file: {filename}")
        self.clear_cache()
        return self.admin.api.change_file_request(
            self.group_name,
            5 if full_replace else 4,
            filename,
            file,
            description,
            need_uncompress,
            self.admin.env,
        )

    def query_deploy_info(self):
        return FileDeployInfo(
            **self.admin.api.query_file_deploy_info(self.group_name, self.admin.env)
        )

    def set_deploy_info(self, info: FileDeployInfo):
        return self.set_group_dir_and_shell(
            info.path,
            info.before_shell,
            info.after_shell,
            info.client_shell,
            info.client_switch,
            executor=info.executor
        )

    def set_group_dir_and_shell(
        self,
        path: str,
        before_shell: str = "",
        after_shell: str = "",
        client_shell: str = "",
        client_switch: bool = False,
        executor: str = "",
    ):
        """设置文件目录和前后置命令

        :param path: 文件下载临时目录
        :param before_shell: 前置命令
        :param after_shell: 后置命令
        :param client_shell: 抓取客户端标识的 shell 语句
        :param client_switch: 是否开启抓取客户端标识
        :param executor: 执行前后置命令的用户名
        :return:
        """
        self.clear_cache()
        return self.admin.api.set_file_dir_and_cmd(
            self.group_name,
            path,
            before_shell,
            after_shell,
            client_shell,
            client_switch,
            self.admin.env,
            executor=executor
        )

    def update_zip_file(self, filename, zip_file, description=""):
        return self.upload_file(filename, zip_file, description, True)

    def get_files(self, version_id=0, version_name=None) -> List[RainbowFile]:
        """k-v型表的 配置项实例化"""
        if version_name:
            l = list(
                filter(lambda x: x['version_name'] == version_name, self.history_versions)
            )
            if len(l) == 0:
                raise RainbowException("历史版本中查不到指定的版本名 {verison_name}")
            if version_id and version_id != l[0]['version_id']:
                raise RainbowException("同时指定了version_id和version_name，但根据name查询到的id不一致 {verison_name}")
            version_id = l[0]['version_id']
        cls = RainbowFile
        if self.is_intranet:
            from .intranet_file import IntranetRainbowFile

            cls = IntranetRainbowFile
        return [
            cls(**i, group=self, is_intranet=self.is_intranet)
            for configs in self.get_info(version_id=version_id)["config_infos"]
            for i in configs["key_values"]
        ]

    @property
    def files(self):
        if self._cache is None:
            self._cache = {i.key: i for i in self.get_files()}
        return self._cache

    def delete_file(self, filename):
        self.clear_cache()
        return self.admin.api.change_file_request(
            self.group_name, 2, filename, env_name=self.admin.env
        )

    def get_file(self, filename) -> Optional[RainbowFile]:
        return self.files.get(filename)

    def download_all_files(self, directory):
        if not os.path.isdir(directory):
            raise ValueError(f"'{directory}' is not exist or not dir")
        for key, file in self.files.items():
            try:
                file.download_to(directory, True)
            except Exception as e:
                logger.error(f"download {key} fail: {e}, skip")

    def __delitem__(self, filename):
        self.delete_file(filename)

    def __getitem__(self, filename):
        return self.files[filename]

    def __setitem__(self, filename, file):
        self.upload_file(filename, file)

    def __contains__(self, filename):
        return filename in self.files
